INSERT INTO standards_paragraphs (id, standard_set, reference_code, paragraph_label, account_key, title, content, keywords, content_hash)
VALUES
  ('kifrs_1116_p22', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 22', 'lease', '사용권자산과 리스부채의 인식', '리스이용자는 리스개시일에 사용권자산과 리스부채를 인식한다.', '리스,사용권자산,리스부채,인식,리스개시일', 'fe0633ac6948ff950bb80a7205f43ae4186338f0f5461879123f58e619f7b926'),
  ('kifrs_1116_p26', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 26', 'lease', '리스부채의 최초 측정', '리스개시일에 리스부채는 그날 현재 지급되지 않은 리스료의 현재가치로 측정한다. 리스의 내재이자율을 쉽게 산정할 수 있으면 그 이자율로, 산정할 수 없으면 리스이용자의 증분차입이자율로 할인한다.', '리스부채,현재가치,할인율,내재이자율,증분차입이자율', '2658bdc674835919826cd1b2453acd5804361629fc955343440c7b281e68d025'),
  ('kifrs_1116_p18', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 18', 'lease', '리스기간의 산정', '리스기간은 리스의 해지불능기간에, 연장선택권을 행사할 것이 상당히 확실한 경우 그 대상 기간과 종료선택권을 행사하지 않을 것이 상당히 확실한 경우 그 대상 기간을 포함하여 산정한다.', '리스기간,연장선택권,종료선택권,해지불능기간', '30c61d82d316547c5b8cf5fe5b17c7740905d116ce58cad102e837ff58be75bb'),
  ('kifrs_1038_p57', 'K-IFRS', 'K-IFRS 제1038호 무형자산', '문단 57', 'development', '개발활동 지출의 자산 인식 요건', '개발활동에서 발생한 무형자산은 기술적 실현가능성, 완성하여 사용하거나 판매하려는 의도와 능력, 미래경제적효익을 창출하는 방법, 개발을 완료하는 데 필요한 자원의 입수가능성, 관련 지출의 신뢰성 있는 측정을 모두 제시할 수 있는 경우에만 인식한다.', '개발비,무형자산,자산화,기술적 실현가능성,미래경제적효익', '61bd70068cb28674944aa9a2e6269f5980446d3d8c0d33b75db541edd66d9597'),
  ('kifrs_1038_p54', 'K-IFRS', 'K-IFRS 제1038호 무형자산', '문단 54', 'development', '연구단계 지출의 비용 처리', '연구(또는 내부 프로젝트의 연구단계)에 대한 지출은 무형자산으로 인식하지 않고 발생시점에 비용으로 인식한다.', '연구비,연구단계,비용,연구개발', 'aff9de8dcb3b7db39c1297e1e40cb28ccf2ff8df5b09cc42704fa0b9fce5a630'),
  ('kifrs_1115_p31', 'K-IFRS', 'K-IFRS 제1115호 고객과의 계약에서 생기는 수익', '문단 31', 'revenue', '수행의무 이행 시 수익 인식', '기업이 고객에게 약속한 재화나 용역, 즉 자산을 이전하여 수행의무를 이행할 때 또는 이행하는 대로 수익을 인식한다. 자산은 고객이 그 자산을 통제할 때 이전된다.', '수익,수행의무,통제 이전,수익인식 시점', '83e9b83c7f4e03cd2afdeda332ec49193205d023a8ed1760149d0bdd5dd44066'),
  ('kifrs_1115_p50', 'K-IFRS', 'K-IFRS 제1115호 고객과의 계약에서 생기는 수익', '문단 50', 'revenue', '변동대가의 추정', '계약에서 약속한 대가에 변동금액이 포함된 경우, 고객에게 약속한 재화나 용역을 이전하고 그 대가로 받을 권리를 갖게 될 금액을 추정한다.', '변동대가,대가 추정,리베이트,할인', '6d423b65bada091c582249f97aaf5290ca6c14c982c89d44000c88c770924671'),
  ('kifrs_1109_p411', 'K-IFRS', 'K-IFRS 제1109호 금융상품', '문단 4.1.1', 'financial_instrument', '금융자산의 분류 기준', '금융자산은 금융자산의 관리를 위한 사업모형과 금융자산의 계약상 현금흐름 특성에 근거하여 상각후원가, 기타포괄손익-공정가치, 당기손익-공정가치 측정 범주로 분류한다.', '금융자산,분류,사업모형,SPPI,계약상 현금흐름', '2c67af5c8d0511e0ac5242c5f9d84763d3705e03fdabca392626ced5f94fe7e2'),
  ('kifrs_1109_p5515', 'K-IFRS', 'K-IFRS 제1109호 금융상품', '문단 5.5.15', 'receivables', '매출채권 기대신용손실 간편법', '매출채권과 계약자산 등에 대해서는 전체기간 기대신용손실에 해당하는 금액으로 손실충당금을 측정하는 간편법을 적용할 수 있다.', '매출채권,기대신용손실,ECL,손실충당금,간편법', '41d2bc6f1f5a44f0439dc4c1a7732713c0095d2b7fe47cf5aaec5bad9a73a841'),
  ('kifrs_1037_p14', 'K-IFRS', 'K-IFRS 제1037호 충당부채, 우발부채 및 우발자산', '문단 14', 'provision', '충당부채의 인식 요건', '충당부채는 과거사건의 결과로 현재의무(법적의무 또는 의제의무)가 존재하고, 그 의무를 이행하기 위해 경제적효익이 있는 자원의 유출 가능성이 높으며, 의무 금액을 신뢰성 있게 추정할 수 있는 경우에 인식한다.', '충당부채,현재의무,자원 유출,신뢰성 있는 추정', '6391a019d3ea5395db2656f68da3208c38ca8ef199c896281ea5715e84a5d383'),
  ('kifrs_1002_p9', 'K-IFRS', 'K-IFRS 제1002호 재고자산', '문단 9', 'inventory', '재고자산의 저가 측정', '재고자산은 취득원가와 순실현가능가치 중 낮은 금액으로 측정한다.', '재고자산,저가법,순실현가능가치,취득원가', '3c810bddc7d61e885ce3236167e286966e3234dd36872bbf9a98289e00e91966'),
  ('kifrs_1007_p6', 'K-IFRS', 'K-IFRS 제1007호 현금흐름표', '문단 6', 'cash', '현금성자산의 정의', '현금성자산은 유동성이 매우 높은 단기 투자자산으로서, 확정된 금액의 현금으로 전환이 용이하고 가치변동의 위험이 경미한 자산을 말한다.', '현금성자산,현금,단기투자,유동성', 'fb9d70ea07eb8f067b72ab843b282170a3a2a122f4d35dfb475f72ca8cea6bb2'),
  ('kgaap_ch13_lease', 'K-GAAP', '일반기업회계기준 제13장 리스', '리스의 분류', 'lease', '금융리스와 운용리스의 분류', '리스는 소유에 따른 위험과 보상의 대부분이 이전되는지에 따라 금융리스와 운용리스로 분류한다. 운용리스의 리스이용자는 리스료를 리스기간에 걸쳐 비용으로 인식하며 리스부채를 계상하지 않는다. K-IFRS 전환 시 사용권자산과 리스부채 계상 여부를 검토해야 한다.', '리스,운용리스,금융리스,비용 인식,부외', 'b338208997752f7103a8a2ebc825b7133b642e814aee8d35ddcef65555d0d0ba'),
  ('kgaap_ch11_development', 'K-GAAP', '일반기업회계기준 제11장 무형자산', '개발비의 인식', 'development', '개발단계 지출의 자산 인식', '개발단계에서 발생한 지출은 기술적 실현가능성, 사용·판매 의도와 능력, 미래경제적효익 창출 가능성, 신뢰성 있는 측정 등 자산 인식요건을 모두 충족하는 경우 개발비의 과목으로 무형자산으로 인식하고, 그 외에는 발생한 기간의 비용으로 처리한다.', '개발비,무형자산,자산화,경상개발비', '649e84e228e447311f06bd799d0f447af2c66cc5e57ed951c3515c264870cd16'),
  ('kgaap_ch16_revenue', 'K-GAAP', '일반기업회계기준 제16장 수익', '재화 판매 수익의 인식', 'revenue', '위험과 보상 이전에 따른 수익 인식', '재화의 판매 수익은 재화 소유에 따른 유의적인 위험과 보상이 구매자에게 이전되고, 수익금액을 신뢰성 있게 측정할 수 있으며, 경제적 효익의 유입 가능성이 매우 높은 경우 등에 인식한다. K-IFRS 제1115호의 수행의무·통제 이전 모형과 접근 방식이 다르다.', '수익,위험과 보상,재화 판매,인도기준', 'd6a720dd49cd32c3ebebfce2ea954cf0c13e30a39c81a515f90ea3933eda2bce'),
  ('kgaap_ch6_securities', 'K-GAAP', '일반기업회계기준 제6장 금융자산·금융부채', '유가증권의 분류', 'financial_instrument', '보유 목적에 따른 유가증권 분류', '유가증권은 취득 목적과 보유 의도에 따라 단기매매증권, 매도가능증권, 만기보유증권 등으로 분류한다. K-IFRS 제1109호의 사업모형·계약상 현금흐름 특성 기준과 분류 체계가 다르므로 전환 시 재분류를 검토해야 한다.', '유가증권,단기매매증권,매도가능증권,만기보유증권,분류', '15f0a35e4135b595dc86eb7868f2355fd220bec9fc9f754200982aecacb718e1'),
  ('kgaap_ch6_receivables', 'K-GAAP', '일반기업회계기준 제6장 금융자산·금융부채', '대손충당금', 'receivables', '대손충당금의 설정', '매출채권 등 수취채권은 회수가 불확실한 금액을 합리적이고 객관적인 기준에 따라 산출한 대손추산액을 대손충당금으로 설정한다. 발생손실에 기초한 접근으로, K-IFRS 제1109호의 기대신용손실 모형과 차이가 있다.', '매출채권,대손충당금,대손추산액,발생손실', '54c2a42f2c8dbbcf90a27fd115fee695d78218599e89ea091418cfb7b4a50a04'),
  ('kgaap_ch14_provision', 'K-GAAP', '일반기업회계기준 제14장 충당부채', '충당부채의 인식', 'provision', '충당부채의 인식 요건', '충당부채는 과거사건의 결과로 현재의무가 존재하고, 그 의무를 이행하기 위해 자원이 유출될 가능성이 매우 높으며, 의무 금액을 신뢰성 있게 추정할 수 있을 때 인식한다.', '충당부채,현재의무,자원 유출,추정', 'ee20b04268a00f6ade9cdf9f5a9c10d6a49f74ea27b8b8af1885e63c467140e8'),
  ('kgaap_ch7_inventory', 'K-GAAP', '일반기업회계기준 제7장 재고자산', '재고자산의 평가', 'inventory', '저가법 평가', '재고자산은 취득원가로 측정하되, 시가가 취득원가보다 낮은 경우에는 시가를 장부금액으로 하는 저가법으로 평가한다.', '재고자산,저가법,시가,평가손실', '70d34f42ec0804978245dccd4c610006dca1dde232c752f7f1af55fcc1637373'),
  ('kgaap_ch2_cash', 'K-GAAP', '일반기업회계기준 제2장 재무제표의 작성과 표시', '현금및현금성자산', 'cash', '현금및현금성자산의 범위', '현금및현금성자산은 통화 및 통화대용증권과 취득 당시 만기가 3개월 이내에 도래하는 유동성이 높은 금융상품 등을 포함한다.', '현금,현금성자산,통화대용증권,만기 3개월', '2a5dd0acdd30509d89c04690c43d2ae8444179c3deafe240bcfa6991e25cf6c8'),
  ('kifrs_1019_p57', 'K-IFRS', 'K-IFRS 제1019호 종업원급여', '문단 57', 'retirement_benefit', '순확정급여부채(자산)의 인식', '확정급여제도의 순확정급여부채(자산)는 확정급여채무의 현재가치에서 사외적립자산의 공정가치를 차감하여 결정한다. 확정급여채무는 예측단위적립방식으로 보험수리적 평가하며, 순확정급여부채(자산)의 재측정요소는 기타포괄손익으로 인식한다.', '퇴직급여,확정급여채무,사외적립자산,순확정급여부채,보험수리적,재측정,OCI', 'f5efbc7d45ddf08e24d28a52bfc74ce9b9205bd474928901ea911e9adcae4ee4'),
  ('kgaap_ch21_severance', 'K-GAAP', '일반기업회계기준 제21장 종업원급여', '퇴직급여충당부채', 'retirement_benefit', '퇴직금추계액 기준 충당부채', '확정급여형 퇴직급여제도의 퇴직급여충당부채는 보고기간말 현재 전 종업원이 일시에 퇴직할 경우 지급하여야 할 퇴직금추계액을 기준으로 인식한다(보험수리적 평가를 요구하지 않음).', '퇴직급여충당부채,퇴직금추계액,확정급여형', '21a44c3db85b25434f040c11219adbaf2241ac3451631ad3de42920e67caba50'),
  ('kifrs_1016_p31', 'K-IFRS', 'K-IFRS 제1016호 유형자산', '문단 31', 'ppe', '재평가모형', '재평가모형을 선택한 경우 공정가치를 신뢰성 있게 측정할 수 있는 유형자산은 재평가일의 공정가치에서 이후의 감가상각누계액과 손상차손누계액을 차감한 재평가금액을 장부금액으로 한다. 재평가로 증가한 금액은 기타포괄손익으로, 감소한 금액은 당기손익으로 인식한다.', '유형자산,재평가모형,공정가치,재평가잉여금,OCI', '604b3697d1941043c37b95a5fff20e6bf3ac40b7b5f35a345631fa2c162eb6d3'),
  ('kifrs_1036_p59', 'K-IFRS', 'K-IFRS 제1036호 자산손상', '문단 59', 'ppe', '손상차손의 인식', '자산의 회수가능액이 장부금액에 미달하면 장부금액을 회수가능액으로 감액하고 그 차액을 손상차손으로 당기손익에 인식한다. 회수가능액은 순공정가치와 사용가치 중 큰 금액이다.', '손상,회수가능액,손상차손,사용가치,순공정가치', '0823d9344567231bc9b20c4d3a391b258f1fbff3827e2f1ec53330cd9e4ea75d'),
  ('kifrs_1040_p33', 'K-IFRS', 'K-IFRS 제1040호 투자부동산', '문단 33', 'investment_property', '공정가치모형', '공정가치모형을 선택한 경우 투자부동산을 공정가치로 측정하고, 공정가치 변동으로 발생하는 손익은 발생한 기간의 당기손익에 반영한다. 공정가치모형에서는 감가상각을 하지 않는다.', '투자부동산,공정가치모형,평가손익,당기손익', 'aec94d04c0b5d64d4457554f0c00e2c8056ff12f5958a22f22fea38668c60c66'),
  ('kifrs_1012_p24', 'K-IFRS', 'K-IFRS 제1012호 법인세', '문단 24', 'deferred_tax_asset', '이연법인세자산의 인식', '차감할 일시적차이가 사용될 수 있는 미래 과세소득의 발생가능성이 높은 경우 그 차이에 대하여 이연법인세자산을 인식한다. 이연법인세자산과 부채는 상계하지 않고 총액으로 인식하며 할인하지 않는다.', '이연법인세자산,일시적차이,총액법,회수가능성,과세소득', 'f8af64ddfff2fbdf2f21d0fee9dd8c6d8dbae50fdd4fdbf3488e6acf64cd6809'),
  ('kifrs_1020_p24', 'K-IFRS', 'K-IFRS 제1020호 정부보조금', '문단 24', 'government_grant', '자산관련 보조금의 표시', '자산관련 정부보조금은 이연수익으로 표시하거나 자산의 장부금액에서 차감하여 표시한다. 어느 방법을 선택하든 관련 자산의 내용연수에 걸쳐 체계적인 기준으로 당기손익에 인식한다.', '정부보조금,자산관련,이연수익,자산차감법', 'b875a7e4b4e3ec3bc8f5479463616837fbdaed4ba0b5e034cd8819d19ae9d69a'),
  ('kifrs_1023_p8', 'K-IFRS', 'K-IFRS 제1023호 차입원가', '문단 8', 'borrowing_cost', '적격자산 차입원가의 자본화', '적격자산의 취득, 건설 또는 생산과 직접 관련된 차입원가는 해당 자산 원가의 일부로 자본화한다. 적격자산은 의도된 용도로 사용하거나 판매할 수 있는 상태가 되는 데 상당한 기간을 필요로 하는 자산이다. 그 밖의 차입원가는 발생 기간의 비용으로 인식한다.', '차입원가,적격자산,자본화,자본화이자율', '4e4156bd71573eb343d411b83355b198673ea36fbae310703548e97c3d89c297'),
  ('kifrs_cf_asset', 'K-IFRS', '재무보고를 위한 개념체계', '4.3', 'other', '자산의 정의', '자산은 과거사건의 결과로 기업이 통제하는 현재의 경제적자원이며, 경제적자원은 경제적효익을 창출할 잠재력을 지닌 권리다. 효익의 유입이 확실하지 않아도 잠재력이 있으면 정의를 충족할 수 있다.', '개념체계,자산,경제적자원,통제,권리', '343669d6e6b51bd007d4cb8f2681bd9501c151902db85b908ad511d67b5edda7'),
  ('kifrs_cf_liability', 'K-IFRS', '재무보고를 위한 개념체계', '4.26', 'other', '부채의 정의', '부채는 과거사건의 결과로 기업이 경제적자원을 이전해야 하는 현재의무다. 의무는 법적 구속뿐 아니라 실무관행 등에서 생기는 의제의무를 포함한다.', '개념체계,부채,현재의무,의제의무', '48e807f3acd4b6a680d64ff845839867e43652bcf93a130d96d36866ee482830'),
  ('kifrs_cf_measure', 'K-IFRS', '재무보고를 위한 개념체계', '6.1', 'other', '측정기준의 선택', '측정기준은 역사적원가와 현행가치(공정가치, 사용가치, 현행원가)로 구분되며, 목적적합성과 표현충실성을 고려해 선택한다. 측정기준에 따라 수익과 비용의 인식 양상이 달라진다.', '측정기준,역사적원가,공정가치,사용가치', 'e0230be7483f1601d4d42813c53beb9cdd2c2b066d8dd6b9df17367cecc6ce9c'),
  ('kifrs_1001_p25', 'K-IFRS', 'K-IFRS 제1001호 재무제표 표시', '문단 25', 'other', '계속기업 가정의 평가', '경영진은 재무제표 작성 시 계속기업으로서의 존속능력을 평가해야 하며, 중대한 불확실성이 있으면 그 내용을 공시한다. 계속기업 가정이 적절하지 않으면 다른 기준으로 작성하고 그 사실을 공시한다.', '계속기업,존속능력,불확실성,공시', 'd1f9d712444e3c027df831182ad9bb32bd7559cba2c5269bc32d3793889c90f7'),
  ('kifrs_1001_p60', 'K-IFRS', 'K-IFRS 제1001호 재무제표 표시', '문단 60', 'other', '유동·비유동 구분 표시', '자산과 부채는 유동성 순서 표시가 더 목적적합한 경우를 제외하고 유동과 비유동으로 구분해 표시한다. 보고기간 후 12개월 이내에 결제 예정인 부채는 유동부채로 분류한다.', '유동,비유동,구분표시,12개월', '1dcf3c6feb4b4b1e23c3e91753c3aade724776cba0e2c294c504deead6f14958'),
  ('kifrs_1001_p32', 'K-IFRS', 'K-IFRS 제1001호 재무제표 표시', '문단 32', 'other', '상계 표시의 금지', '자산과 부채, 수익과 비용은 기준서가 요구하거나 허용하는 경우가 아니면 상계하지 않는다. 상계 표시는 거래의 실질 이해를 저해할 수 있다.', '상계금지,총액표시,실질', '252be40090beb5e27d4161715ad12375a00ba8ade50b74163e508686047b615d'),
  ('kifrs_1001_p81', 'K-IFRS', 'K-IFRS 제1001호 재무제표 표시', '문단 81A', 'other', '당기순손익과 기타포괄손익의 표시', '포괄손익계산서는 당기순손익과 기타포괄손익(OCI)을 구분해 표시하며, OCI 항목은 후속적으로 당기손익으로 재분류되는 항목과 되지 않는 항목으로 나누어 표시한다.', '포괄손익,OCI,재분류,표시', 'f1ca691cd0ba2fce1d65223c354368733dca1bf45786e7012e509f3b14dc3b97'),
  ('kifrs_1002_p25', 'K-IFRS', 'K-IFRS 제1002호 재고자산', '문단 25', 'inventory', '원가산정방법', '재고자산 원가는 개별법을 적용할 수 없는 경우 선입선출법 또는 가중평균법으로 산정한다. 후입선출법(LIFO)은 허용되지 않는다.', '선입선출,가중평균,후입선출금지,단위원가', 'd69b89cdceaa0211507a3adfc8bade55d6452a4170936cb819a06291557a04cc'),
  ('kifrs_1002_p33', 'K-IFRS', 'K-IFRS 제1002호 재고자산', '문단 33', 'inventory', '평가손실의 환입', '순실현가능가치 하락으로 평가손실을 인식한 뒤 그 가치가 회복되면, 최초 장부금액을 한도로 평가손실을 환입해 매출원가에서 차감한다.', '순실현가능가치,평가손실환입,저가법', '9e87fb4ce774c28744f2b03f51d3424039c9c38a146ed10094e2a47686ca50a7'),
  ('kifrs_1007_p10', 'K-IFRS', 'K-IFRS 제1007호 현금흐름표', '문단 10', 'cash', '활동별 현금흐름 구분', '현금흐름표는 영업활동, 투자활동, 재무활동으로 구분해 보고한다. 영업활동 현금흐름은 직접법 또는 간접법으로 표시할 수 있으며 직접법이 권장된다.', '영업활동,투자활동,재무활동,직접법,간접법', '21301e6927338c50e4cf5c53cb526678037ec155c534ea546a20ed7970432e4f'),
  ('kifrs_1007_p31', 'K-IFRS', 'K-IFRS 제1007호 현금흐름표', '문단 31', 'cash', '이자와 배당금의 분류', '이자와 배당금의 수취·지급은 매기 일관되게 영업, 투자 또는 재무활동으로 분류한다. 분류 선택은 회계정책으로서 계속 적용해야 한다.', '이자,배당금,분류,일관성', 'a6d7f1fc0e857f33cf282637730d47873b876969c2ed1292c241fcd2b15e4fe7'),
  ('kifrs_1008_p19', 'K-IFRS', 'K-IFRS 제1008호 회계정책, 회계추정치 변경과 오류', '문단 19', 'other', '회계정책 변경의 소급적용', '회계정책 변경은 경과규정이 없는 한 소급적용하며, 비교표시되는 과거기간의 금액을 재작성한다. 소급적용이 실무적으로 불가능한 경우 가능한 최초 기간부터 적용한다.', '회계정책변경,소급적용,재작성', '24d09505ec0141d993f46c53bb959e932c2a03ac841e43c69366ab997c509abe'),
  ('kifrs_1008_p36', 'K-IFRS', 'K-IFRS 제1008호 회계정책, 회계추정치 변경과 오류', '문단 36', 'other', '회계추정치 변경의 전진적용', '회계추정치 변경(내용연수, 대손율, 충당부채 추정 등)은 변경이 발생한 기간과 미래기간에 전진적으로 인식하며 과거 재무제표를 수정하지 않는다. 중요한 전기오류는 소급재작성한다.', '회계추정,전진적용,전기오류,소급재작성', '1aab65393a8ec064a6129262a5a53437653f94775efc814e19c4b76aef0d4ca8'),
  ('kifrs_1010_p8', 'K-IFRS', 'K-IFRS 제1010호 보고기간후사건', '문단 8', 'other', '수정을 요하는 사건과 요하지 않는 사건', '보고기간 말 존재했던 상황의 증거를 제공하는 사건(수정사건)은 재무제표 금액을 수정하고, 보고기간 후 발생한 상황(비수정사건)은 중요하면 공시만 한다. 배당 선언은 비수정사건이다.', '보고기간후사건,수정사건,비수정사건,공시', '1c562c76d5140b7cfd9b180357637c086afa01cdb90a9832376181cc07af7f1e'),
  ('kifrs_1012_p15', 'K-IFRS', 'K-IFRS 제1012호 법인세', '문단 15', 'deferred_tax_liability', '이연법인세부채의 인식', '가산할 일시적차이에 대해서는 영업권 최초인식 등 예외를 제외하고 모두 이연법인세부채를 인식한다. 자산 장부금액을 회수할 때 세무상 더 많은 과세소득이 생기는 차이가 대상이다.', '이연법인세부채,가산할일시적차이,인식', 'cffedd507542c96b48943badae8cb92e256a2cadc293c883436207473c6a90ba'),
  ('kifrs_1012_p47', 'K-IFRS', 'K-IFRS 제1012호 법인세', '문단 47', 'deferred_tax_asset', '적용 세율', '이연법인세 자산과 부채는 보고기간 말까지 제정되었거나 실질적으로 제정된 세율 중 자산이 실현되거나 부채가 결제될 기간에 적용될 것으로 예상되는 세율로 측정한다.', '세율,실질적제정,측정', '478e14be4856d76823a043a61ff16dd0403852975e581e71dc9a17145d0c170e'),
  ('kifrs_1012_p71', 'K-IFRS', 'K-IFRS 제1012호 법인세', '문단 71', 'deferred_tax_asset', '상계 표시 요건', '당기법인세 자산·부채는 상계권리와 순액결제 의도가 있을 때, 이연법인세 자산·부채는 동일 과세당국 관련 등 요건을 충족할 때에만 상계해 표시한다.', '상계,과세당국,표시요건', '40c1e32945e7dbd120fc10df11ea8980ce87dc75c55acae7ffc8c09e3c1802d4'),
  ('kifrs_1016_p16', 'K-IFRS', 'K-IFRS 제1016호 유형자산', '문단 16', 'ppe', '취득원가의 구성', '유형자산 원가는 구입가격, 의도된 방식으로 가동 가능한 상태까지의 직접관련원가, 그리고 해체·제거·복구원가의 최초 추정치로 구성된다.', '취득원가,직접관련원가,복구원가', '03c99a899abfa229565e82f2a307b9000d20bd8070b803fe454a52d2ddc5e8c4'),
  ('kifrs_1016_p43', 'K-IFRS', 'K-IFRS 제1016호 유형자산', '문단 43', 'ppe', '구성요소별 감가상각', '유형자산 원가 중 유의적인 부분은 별도로 구분해 감가상각한다. 감가상각방법과 내용연수, 잔존가치는 적어도 매 회계연도 말 재검토하고 변경은 회계추정치 변경으로 처리한다.', '감가상각,구성요소,내용연수,재검토', '80cf03e69ca4fa9dafa1b1a8083daf58e2c0912acc9bbacc40e7183d8f1e4d04'),
  ('kifrs_1016_p67', 'K-IFRS', 'K-IFRS 제1016호 유형자산', '문단 67', 'ppe', '유형자산의 제거', '유형자산은 처분하거나 사용·처분으로 미래경제적효익이 기대되지 않을 때 제거하며, 제거손익은 순처분대가와 장부금액의 차이로 당기손익에 인식한다.', '제거,처분손익,장부금액', '1ba22fe844f275eb021a55de93d0dd9798974138eb53da882315b70d9d747444'),
  ('kifrs_1019_p120', 'K-IFRS', 'K-IFRS 제1019호 종업원급여', '문단 120', 'retirement_benefit', '재측정요소의 기타포괄손익 인식', '확정급여제도의 재측정요소(보험수리적손익, 사외적립자산 수익 중 순이자 제외분)는 기타포괄손익으로 인식하며 후속적으로 당기손익으로 재분류하지 않는다.', '재측정요소,보험수리적손익,OCI', '7e13afbb0d01d0021bd5ec6347d6e675571a7a578fab4789250736a7c2bcfca1'),
  ('kifrs_1019_p11', 'K-IFRS', 'K-IFRS 제1019호 종업원급여', '문단 11', 'retirement_benefit', '단기종업원급여', '임금, 유급휴가, 상여 등 단기종업원급여는 근무용역 제공 시 할인하지 않은 금액으로 비용과 부채를 인식한다.', '단기종업원급여,유급휴가,상여', '58cbf3ddc88a37740f5526e59aacd7200cda5da8e5a871987ae98dffa3bb4051'),
  ('kifrs_1021_p9', 'K-IFRS', 'K-IFRS 제1021호 환율변동효과', '문단 9', 'other', '기능통화의 결정', '기능통화는 기업이 영업하는 주된 경제 환경의 통화로, 재화·용역의 표시가격과 원가에 주로 영향을 미치는 통화 등을 고려해 결정한다. 재무제표는 어떤 통화로도 표시할 수 있으나 측정은 기능통화로 한다.', '기능통화,표시통화,주된경제환경', '4f8c3aed0159493735caeb2fa11b59a9eab8e057def981415f1f896dfee227b8'),
  ('kifrs_1021_p23', 'K-IFRS', 'K-IFRS 제1021호 환율변동효과', '문단 23', 'other', '화폐성항목의 보고기간말 환산', '보고기간 말 화폐성 외화항목은 마감환율로 환산하고 환산차이는 당기손익으로 인식한다. 역사적원가로 측정하는 비화폐성항목은 거래일 환율을 유지한다.', '화폐성항목,마감환율,환산차이', '17d23b3619e3a2c34f882efc786886e4fa4a92ed8f67150460291b0969d1a733'),
  ('kifrs_1110_p7', 'K-IFRS', 'K-IFRS 제1110호 연결재무제표', '문단 7', 'other', '지배력의 세 요소', '투자자는 피투자자에 대한 힘, 변동이익에 대한 노출 또는 권리, 이익에 영향을 미치기 위해 힘을 사용하는 능력의 세 요소를 모두 가질 때 지배한다. 지배력이 있으면 연결재무제표를 작성한다.', '지배력,힘,변동이익,연결', '4d819f60e9b0eaa8fea744d4cfb5df7c74e8a96f449ca148fb19856114a1e882'),
  ('kifrs_1110_p22', 'K-IFRS', 'K-IFRS 제1110호 연결재무제표', '문단 22', 'other', '비지배지분의 표시', '비지배지분은 연결재무상태표에서 지배기업 소유주지분과 구분하여 자본으로 표시한다. 총포괄손익은 비지배지분이 부(-)의 잔액이 되더라도 귀속시킨다.', '비지배지분,자본,귀속', 'ffb9d05f16d2bb1c912bcd65d255023b7ab2174d0016156d6f4f2f297a576d44'),
  ('kifrs_1028_p10', 'K-IFRS', 'K-IFRS 제1028호 관계기업과 공동기업에 대한 투자', '문단 10', 'other', '지분법 적용', '유의적인 영향력이 있는 관계기업 투자는 지분법으로 회계처리한다. 취득 후 피투자자의 당기순손익 중 투자자 몫을 투자 장부금액에 가감하고 배당은 장부금액에서 차감한다.', '지분법,유의적영향력,관계기업', '7453e0316b0c7c43bd403d6ac16e49a5463ff6b76e8b23b6b004435aeb8191e2'),
  ('kifrs_1032_p15', 'K-IFRS', 'K-IFRS 제1032호 금융상품: 표시', '문단 15', 'share_capital', '금융부채와 지분상품의 구분', '발행자는 계약의 실질에 따라 금융상품을 금융부채 또는 지분상품으로 분류한다. 현금 등 금융자산을 인도할 계약상 의무가 있으면 금융부채이고, 그렇지 않으면 지분상품이다.', '금융부채,지분상품,분류,계약실질', 'ea64fddb142acdd65993cc4dce5f450125e18928ea41814ad2160edb1a597fba'),
  ('kifrs_1036_p9', 'K-IFRS', 'K-IFRS 제1036호 자산손상', '문단 9', 'ppe', '손상검사의 시기', '매 보고기간 말 자산 손상 징후를 검토하고, 징후가 있으면 회수가능액을 추정한다. 영업권과 내용연수 비한정 무형자산은 징후와 무관하게 매년 손상검사를 한다.', '손상징후,손상검사,영업권,매년', '98965dfdbd7df7ed83a4e8542216029679f027504b33c98de3017f4dfcdde01e'),
  ('kifrs_1036_p114', 'K-IFRS', 'K-IFRS 제1036호 자산손상', '문단 114', 'ppe', '손상차손의 환입', '과거에 인식한 손상차손은 회수가능액 추정에 사용된 가정이 변동되어 회복된 경우, 손상을 인식하지 않았을 경우의 장부금액을 한도로 환입한다. 영업권 손상차손은 환입하지 않는다.', '손상환입,한도,영업권환입금지', '1decca73d9801fde30aa876efff372d6208cb16f4e9f37bfa20706c6ad2879ad'),
  ('kifrs_1037_p36', 'K-IFRS', 'K-IFRS 제1037호 충당부채, 우발부채 및 우발자산', '문단 36', 'provision', '최선의 추정치와 현재가치', '충당부채는 보고기간 말 의무 이행에 필요한 지출에 대한 최선의 추정치로 측정하며, 화폐의 시간가치가 중요한 경우 현재가치로 평가한다.', '최선의추정치,현재가치,측정', '92bd2779f064532daf398ba361f9bf5445ca63c06b1b952c5fb4b3043f915dad'),
  ('kifrs_1037_p27', 'K-IFRS', 'K-IFRS 제1037호 충당부채, 우발부채 및 우발자산', '문단 27', 'provision', '우발부채의 공시', '우발부채는 재무제표에 부채로 인식하지 않고, 자원 유출 가능성이 희박하지 않는 한 그 내용을 주석으로 공시한다. 우발자산도 인식하지 않으며 유입이 거의 확실할 때에만 관련 자산을 인식한다.', '우발부채,우발자산,주석공시', 'c1962e12436a3197dca60389196599af9fc7ad4d29cbc0ac49999c363feadaf5'),
  ('kifrs_1038_p54r', 'K-IFRS', 'K-IFRS 제1038호 무형자산', '문단 54', 'development', '연구단계 지출의 비용처리', '연구단계 지출은 미래경제적효익 창출 여부를 제시할 수 없으므로 발생시점에 비용으로 인식한다. 연구와 개발을 구분할 수 없으면 전액 연구단계로 본다.', '연구단계,비용인식,구분불가', '62145f517752f2f930efaee263c628201187fe75ff7c5b250bcf3e9be3fd6d95'),
  ('kifrs_1038_p107', 'K-IFRS', 'K-IFRS 제1038호 무형자산', '문단 107', 'development', '내용연수 비한정 무형자산', '내용연수가 비한정인 무형자산은 상각하지 않는 대신 매년 그리고 손상 징후가 있을 때 손상검사를 수행한다. 비한정 판단은 매기 재검토한다.', '내용연수비한정,상각금지,손상검사', 'd65dce3e1bec6af308230048551c14f07305a57d4e6c6916630c0fa5c04472e8'),
  ('kifrs_1040_p57', 'K-IFRS', 'K-IFRS 제1040호 투자부동산', '문단 57', 'investment_property', '용도변경과 계정대체', '투자부동산의 계정대체는 사용목적 변경이 실제로 일어난 경우에만 한다. 공정가치모형 적용 투자부동산을 자가사용으로 대체하면 대체시점 공정가치를 간주원가로 한다.', '용도변경,계정대체,간주원가', '310f7f67afc20e52e6628271fa9f0ca537139f34d9c5bc7bf76ee2aecae589df'),
  ('kifrs_1102_p10', 'K-IFRS', 'K-IFRS 제1102호 주식기준보상', '문단 10', 'other', '지분결제형 주식기준보상', '지분결제형 주식기준보상은 제공받는 재화나 용역을 부여일 지분상품 공정가치로 측정해 가득기간에 걸쳐 비용과 자본으로 인식한다. 시장조건이 아닌 가득조건은 수량 추정에 반영한다.', '주식기준보상,지분결제형,부여일공정가치,가득기간', '35be6b5183440d716b70e5e72a04a3d5cdbf644673993424d47047dba5f87215'),
  ('kifrs_1102_p30', 'K-IFRS', 'K-IFRS 제1102호 주식기준보상', '문단 30', 'other', '현금결제형 주식기준보상', '현금결제형(주가차액보상권 등)은 부채로 인식하고 결제될 때까지 매 보고기간 말 공정가치로 재측정하며 변동을 당기손익에 반영한다.', '현금결제형,주가차액보상권,재측정', 'bc130f9b325afe6ff3262cda94793fe65710e0ea8f55a4ff50b34109e2947ac7'),
  ('kifrs_1103_p4', 'K-IFRS', 'K-IFRS 제1103호 사업결합', '문단 4', 'other', '취득법의 적용', '모든 사업결합은 취득법으로 회계처리한다. 취득자를 식별하고, 취득일을 결정하며, 이전대가와 식별가능한 취득 자산·인수 부채를 공정가치로 측정한다.', '사업결합,취득법,이전대가,공정가치', 'b2da54c368f56853595e7f97611bb86532dba04694db0659f51c7791dbafc2e0'),
  ('kifrs_1103_p32', 'K-IFRS', 'K-IFRS 제1103호 사업결합', '문단 32', 'other', '영업권의 인식과 염가매수차익', '이전대가가 식별가능한 순자산 공정가치를 초과하는 금액은 영업권으로 인식한다. 반대로 순자산 공정가치가 이전대가를 초과하면 재검토 후 그 차익을 당기손익(염가매수차익)으로 인식한다.', '영업권,염가매수차익,순자산공정가치', '49fe9a48291856c15ec0f10811974968f95c8b92a049bcb68d9e315b9eee81c9'),
  ('kifrs_1105_p15', 'K-IFRS', 'K-IFRS 제1105호 매각예정비유동자산과 중단영업', '문단 15', 'other', '매각예정 분류와 측정', '매각예정으로 분류한 비유동자산은 장부금액과 순공정가치 중 작은 금액으로 측정하고 감가상각을 중단한다. 중단영업의 성과는 별도 표시한다.', '매각예정,순공정가치,감가상각중단,중단영업', '117570e8a7f67ddc7bc5a96d168e6a6840d56d1142f08151c709c13ae89f3280'),
  ('kifrs_1108_p5', 'K-IFRS', 'K-IFRS 제1108호 영업부문', '문단 5', 'other', '영업부문의 식별', '영업부문은 수익과 비용을 발생시키고, 최고영업의사결정자가 성과를 정기적으로 검토하며, 구분된 재무정보가 이용가능한 기업의 구성단위다. 보고부문별로 수익, 손익 등을 공시한다.', '영업부문,최고영업의사결정자,보고부문', '1d0a54ce895f57c931d4cef1aad8128ef35940063f9cbaeef13cf2ea135fe638'),
  ('kifrs_1109_p421', 'K-IFRS', 'K-IFRS 제1109호 금융상품', '문단 4.1.1', 'financial_instrument', '사업모형과 현금흐름 특성에 따른 분류', '금융자산은 관리하는 사업모형과 계약상 현금흐름 특성(원리금 지급만으로 구성되는지, SPPI)에 따라 상각후원가, 기타포괄손익-공정가치, 당기손익-공정가치로 분류한다.', '사업모형,SPPI,상각후원가,분류', 'f5fec97e19ea08764b2b3dec9fc893a77b7f91373c42d2e3aa5411656f739b3e'),
  ('kifrs_1109_p551g', 'K-IFRS', 'K-IFRS 제1109호 금융상품', '문단 5.5', 'receivables', '기대신용손실의 3단계 모형', '기대신용손실은 최초인식 후 신용위험의 유의적 증가 여부에 따라 12개월 또는 전체기간 기준으로 측정한다. 매출채권 등에는 전체기간 기대신용손실을 적용하는 간편법을 사용할 수 있다.', '기대신용손실,3단계,간편법,신용위험', 'cd6e88f139f1b6a873e3cc0baec9961271b0efa3bbfd7953c986ebe90ef1b599'),
  ('kifrs_1113_p9', 'K-IFRS', 'K-IFRS 제1113호 공정가치 측정', '문단 9', 'other', '공정가치의 정의', '공정가치는 측정일에 시장참여자 사이의 정상거래에서 자산을 매도하면서 받거나 부채를 이전하면서 지급하게 될 가격(유출가격)이다.', '공정가치,유출가격,시장참여자,정상거래', 'f385af50c8e0f39a7f379ff169d192e7f7e4a3cf8da1d2450252e890c5a5cbff'),
  ('kifrs_1113_p72', 'K-IFRS', 'K-IFRS 제1113호 공정가치 측정', '문단 72', 'other', '공정가치 서열체계', '공정가치 측정에 사용한 투입변수는 활성시장 공시가격(수준 1), 관측가능한 기타 투입변수(수준 2), 관측불가능한 투입변수(수준 3)의 서열체계로 구분해 공시한다.', '서열체계,수준1,수준2,수준3', 'ac80e3efb8acd2523af741a1e135f35feb779ddc6be2b3f05902cbfc5f2ea516'),
  ('kifrs_1115_p9', 'K-IFRS', 'K-IFRS 제1115호 고객과의 계약에서 생기는 수익', '문단 9', 'revenue', '수익인식 5단계 모형', '수익은 계약 식별, 수행의무 식별, 거래가격 산정, 거래가격 배분, 수행의무 이행 시 수익인식의 5단계를 거쳐 인식한다. 고객에게 재화나 용역에 대한 통제가 이전될 때 수익을 인식한다.', '5단계모형,수행의무,거래가격,통제이전', '81c87b25ae621018dd4da2f038a9ce6a63432e4da5ca8ecde95157e5ebb9e9a8'),
  ('kifrs_1115_p56', 'K-IFRS', 'K-IFRS 제1115호 고객과의 계약에서 생기는 수익', '문단 56', 'revenue', '변동대가의 제약', '변동대가(리베이트, 환불, 성과보너스 등)는 불확실성이 해소될 때 유의적인 수익 환입이 발생하지 않을 가능성이 매우 높은 금액까지만 거래가격에 포함한다.', '변동대가,제약,환불부채', '6cb5244803d4ffb9328fd5468ae13cd110d6bca5714748437956c0359cfd7307'),
  ('kifrs_1115_pb34', 'K-IFRS', 'K-IFRS 제1115호 고객과의 계약에서 생기는 수익', '적용지침 B34', 'revenue', '본인과 대리인의 구분', '재화나 용역이 고객에게 이전되기 전에 그것을 통제하면 본인으로서 총액으로, 통제하지 못하고 주선만 하면 대리인으로서 수수료 순액으로 수익을 인식한다.', '본인,대리인,총액,순액', '8ea2440dcdb6d77ecc10993b48eedb360cb890da6e01dbb848727cc276d3f216'),
  ('kifrs_1116_p5', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 5', 'lease', '단기리스와 소액자산 리스의 예외', '리스이용자는 12개월 이하 단기리스와 소액 기초자산 리스에 대해 사용권자산과 리스부채를 인식하지 않고 리스료를 기간에 걸쳐 비용으로 인식하는 선택을 할 수 있다.', '단기리스,소액자산,인식면제', '3be0abff845a0fa869e06969f4c93d765ddc78a655a97fac0a8c467b99c653ab'),
  ('kifrs_1116_p40', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 40', 'lease', '리스부채의 재측정', '리스기간 변경, 매수선택권 평가 변경, 지수나 요율에 따른 리스료 변동 등이 있으면 수정 할인율 또는 기존 할인율로 리스부채를 재측정하고 사용권자산을 조정한다.', '리스부채재측정,리스변경,할인율', 'ee97a3f73a9ef05de28d7216dbc921d49a5612fbcc9de44ea09c6137a4c9e406'),
  ('kifrs_1116_p61', 'K-IFRS', 'K-IFRS 제1116호 리스', '문단 61', 'lease', '리스제공자의 리스 분류', '리스제공자는 기초자산 소유에 따른 위험과 보상의 대부분을 이전하는 리스를 금융리스로, 그 외는 운용리스로 분류한다. 리스이용자와 달리 이중 회계모형이 유지된다.', '리스제공자,금융리스,운용리스', '30d997b335948c0fc9733f3c320c7063a5ee63d5370c499e8962ffe38a124139'),
  ('kifrs_1033_p10', 'K-IFRS', 'K-IFRS 제1033호 주당이익', '문단 10', 'other', '기본주당이익', '기본주당이익은 지배기업 보통주 귀속 당기순손익을 가중평균 유통보통주식수로 나누어 산정한다. 희석주당이익은 잠재적보통주의 희석효과를 반영한다.', '기본주당이익,희석주당이익,가중평균주식수', '7a2e427b85fab26dea996340bae9dde70ea3f987623ba3efd4ff6213178dce0a'),
  ('kifrs_1117_p32', 'K-IFRS', 'K-IFRS 제1117호 보험계약', '문단 32', 'other', '보험계약부채의 측정', '보험계약부채는 미래현금흐름의 추정치, 화폐의 시간가치, 비금융위험 조정, 그리고 미실현이익인 보험계약마진(CSM)으로 구성해 측정한다.', '보험계약,이행현금흐름,보험계약마진', '2619a74adf95bb4bb44ef5d240c6bfc4363ccc440b20aba2f4ff3567aef09911')
